import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Option, type SelectValue } from './Option';
import { Select } from './Select';

const meta = {
  title: 'Components/Option',
  component: Option,
  tags: ['autodocs'],
  argTypes: {
    label: { control: 'text' },
    disabled: { control: 'boolean' },
    value: { control: false },
    children: { control: false },
  },
  args: {
    // Required prop; the story renders options inside a Select via `render`.
    value: 'a',
  },
} satisfies Meta<typeof Option>;

export default meta;
type Story = StoryObj<typeof meta>;

export const InsideSelect: Story = {
  name: 'Inside a Select',
  render: () => {
    const [value, setValue] = useState<SelectValue | SelectValue[]>('a');
    return (
      <Select value={value} onChange={setValue} style={{ width: 220 }} placeholder="Pick one">
        <Option value="a" label="Available">
          Available
        </Option>
        <Option value="b" label="Also available">
          Also available
        </Option>
        <Option value="c" label="Disabled" disabled>
          Disabled option
        </Option>
      </Select>
    );
  },
};

import { createContext, type ReactNode, useContext } from 'react';
import { cls, useNamespace } from '../../utils';

/** A single selectable value. */
export type SelectValue = string | number;

export interface OptionProps {
  /** The value committed when this option is chosen. */
  value: SelectValue;
  /** Display label. Defaults to the text of `children`. */
  label?: string;
  /** Disable selecting this option. */
  disabled?: boolean;
  /** Custom content; falls back to `label` or `value`. */
  children?: ReactNode;
}

export interface SelectContextValue {
  /** Currently selected value(s). */
  selectedValues: SelectValue[];
  /** Whether a given value is selected. */
  isSelected: (value: SelectValue) => boolean;
  /** Commit a value (toggle in multiple mode). */
  onSelect: (value: SelectValue) => void;
  /** Multiple-selection mode. */
  multiple: boolean;
  /** Current filter query (filterable mode). */
  query: string;
  /** Value currently highlighted by keyboard navigation. */
  hoveringValue: SelectValue | null;
  /** Build the stable DOM id for an option, scoped to this Select instance. */
  optionId: (value: SelectValue) => string;
}

export const SelectContext = createContext<SelectContextValue | null>(null);

/**
 * `Option` renders only inside a `Select`. The parent reads its props to build
 * the dropdown list, so it can also be rendered directly when a context exists.
 */
export function Option(props: OptionProps) {
  const { value, label, disabled = false, children } = props;
  const ns = useNamespace('select-dropdown');
  const context = useContext(SelectContext);

  if (!context) {
    return null;
  }

  const selected = context.isSelected(value);
  const hovering = context.hoveringValue === value;

  const classes = cls(
    ns.e('item'),
    ns.is('selected', selected),
    ns.is('hovering', hovering),
    ns.is('disabled', disabled),
  );

  return (
    <li
      id={context.optionId(value)}
      role="option"
      aria-selected={selected}
      aria-disabled={disabled || undefined}
      className={classes}
      onClick={() => {
        if (!disabled) {
          context.onSelect(value);
        }
      }}
    >
      <span>{children ?? label ?? String(value)}</span>
    </li>
  );
}

import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Select } from './Select';
import { Option, type SelectValue } from './Option';
import { Space } from '../Space';
import { Text } from '../Text';

const FRAMEWORKS = [
  { value: 'react', label: 'React' },
  { value: 'vue', label: 'Vue' },
  { value: 'svelte', label: 'Svelte' },
  { value: 'solid', label: 'Solid' },
  { value: 'angular', label: 'Angular', disabled: true },
];

const meta = {
  title: 'Components/Select',
  component: Select,
  tags: ['autodocs'],
  argTypes: {
    multiple: { control: 'boolean' },
    disabled: { control: 'boolean' },
    clearable: { control: 'boolean' },
    filterable: { control: 'boolean' },
    loading: { control: 'boolean' },
    size: { control: 'inline-radio', options: ['large', 'default', 'small'] },
    placeholder: { control: 'text' },
    value: { control: false },
    children: { control: false },
  },
  args: {
    placeholder: 'Framework',
  },
} satisfies Meta<typeof Select>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Single: Story = {
  render: (args) => {
    const [single, setSingle] = useState<SelectValue | SelectValue[]>('react');
    return (
      <Space align="center">
        <Select {...args} value={single} onChange={setSingle} clearable style={{ width: 220 }}>
          {FRAMEWORKS.map((f) => (
            <Option key={f.value} value={f.value} label={f.label} disabled={f.disabled}>
              {f.label}
            </Option>
          ))}
        </Select>
        <Text type="info" size="small">
          value: {String(single) || '—'}
        </Text>
      </Space>
    );
  },
};

export const Multiple: Story = {
  render: () => {
    const [multiple, setMultiple] = useState<SelectValue | SelectValue[]>(['react', 'vue']);
    return (
      <Select
        value={multiple}
        onChange={setMultiple}
        multiple
        clearable
        style={{ width: 320 }}
        placeholder="Frameworks"
      >
        {FRAMEWORKS.map((f) => (
          <Option key={f.value} value={f.value} label={f.label} disabled={f.disabled}>
            {f.label}
          </Option>
        ))}
      </Select>
    );
  },
};

export const Filterable: Story = {
  render: () => {
    const [filtered, setFiltered] = useState<SelectValue | SelectValue[]>('');
    return (
      <Select
        value={filtered}
        onChange={setFiltered}
        filterable
        clearable
        style={{ width: 220 }}
        placeholder="Search framework"
      >
        {FRAMEWORKS.map((f) => (
          <Option key={f.value} value={f.value} label={f.label} disabled={f.disabled}>
            {f.label}
          </Option>
        ))}
      </Select>
    );
  },
};

import {
  Children,
  type CSSProperties,
  forwardRef,
  isValidElement,
  type KeyboardEvent,
  type ReactElement,
  type ReactNode,
  useId,
  useMemo,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { Popper } from '../Overlay';
import { Option, type OptionProps, SelectContext, type SelectValue } from './Option';

export interface SelectProps {
  /** Controlled value. Array when `multiple`. */
  value?: SelectValue | SelectValue[];
  /** Initial value for the uncontrolled mode. */
  defaultValue?: SelectValue | SelectValue[];
  /** Fired with the next value whenever the selection changes. */
  onChange?: (value: SelectValue | SelectValue[]) => void;
  /** Allow selecting multiple values, rendered as removable tags. */
  multiple?: boolean;
  /** Disable the control. */
  disabled?: boolean;
  /** Show a clear button when there is a value. */
  clearable?: boolean;
  /** Allow typing to filter the options. */
  filterable?: boolean;
  /** Placeholder shown when nothing is selected. */
  placeholder?: string;
  /** Size. Falls back to the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Show a loading hint inside the dropdown. */
  loading?: boolean;
  /** Text shown when there are no options. */
  noDataText?: string;
  /** Text shown when the query matches no options. */
  noMatchText?: string;
  /** Native `name` attribute, mirrored to a hidden input. */
  name?: string;
  /** Accessible name for the `combobox` role. */
  'aria-label'?: string;
  /** ID of the element labelling the `combobox` role. */
  'aria-labelledby'?: string;
  /** Fired when the dropdown opens or closes. */
  onVisibleChange?: (visible: boolean) => void;
  /** Fired when the clear button is pressed. */
  onClear?: () => void;
  /** Fired when a tag is removed in multiple mode. */
  onRemoveTag?: (value: SelectValue) => void;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
  /** `Option` elements. */
  children?: ReactNode;
}

interface OptionMeta {
  value: SelectValue;
  label: string;
  disabled: boolean;
  element: ReactElement<OptionProps>;
}

function CaretIcon() {
  return (
    <svg viewBox="0 0 1024 1024" width="1em" height="1em" aria-hidden="true">
      <path
        fill="currentColor"
        d="M831.872 340.864 512 652.672 192.128 340.864a30.592 30.592 0 0 0-42.752 0 29.12 29.12 0 0 0 0 41.6L489.664 714.24a32 32 0 0 0 44.672 0l340.288-331.776a29.12 29.12 0 0 0 0-41.6 30.592 30.592 0 0 0-42.752 0z"
      />
    </svg>
  );
}

function ClearIcon() {
  return (
    <svg viewBox="0 0 1024 1024" width="1em" height="1em" aria-hidden="true">
      <path
        fill="currentColor"
        d="M512 64a448 448 0 1 1 0 896 448 448 0 0 1 0-896zm0 393.664L407.936 353.6a38.4 38.4 0 1 0-54.336 54.336L457.664 512 353.6 616.064a38.4 38.4 0 1 0 54.336 54.336L512 566.336 616.064 670.4a38.4 38.4 0 1 0 54.336-54.336L566.336 512 670.4 407.936a38.4 38.4 0 1 0-54.336-54.336L512 457.664z"
      />
    </svg>
  );
}

function CloseIcon() {
  return (
    <svg viewBox="0 0 24 24" width="1em" height="1em" aria-hidden="true">
      <path
        fill="currentColor"
        d="M12 10.586 6.707 5.293a1 1 0 0 0-1.414 1.414L10.586 12l-5.293 5.293a1 1 0 1 0 1.414 1.414L12 13.414l5.293 5.293a1 1 0 0 0 1.414-1.414L13.414 12l5.293-5.293a1 1 0 0 0-1.414-1.414L12 10.586Z"
      />
    </svg>
  );
}

function isOption(child: ReactNode): child is ReactElement<OptionProps> {
  return isValidElement(child) && child.type === Option;
}

function reactNodeToText(node: ReactNode): string {
  if (node === null || node === undefined || typeof node === 'boolean') {
    return '';
  }
  if (typeof node === 'string' || typeof node === 'number') {
    return String(node);
  }
  if (Array.isArray(node)) {
    return node.map(reactNodeToText).join('');
  }
  if (isValidElement(node)) {
    return reactNodeToText((node.props as { children?: ReactNode }).children);
  }
  return '';
}

export const Select = forwardRef<HTMLDivElement, SelectProps>(function Select(props, ref) {
  const {
    value,
    defaultValue,
    onChange,
    multiple = false,
    disabled: disabledProp,
    clearable = false,
    filterable = false,
    placeholder = 'Select',
    size: sizeProp,
    loading = false,
    noDataText = 'No data',
    noMatchText = 'No matching data',
    name,
    'aria-label': ariaLabel,
    'aria-labelledby': ariaLabelledby,
    onVisibleChange,
    onClear,
    onRemoveTag,
    className,
    style,
    children,
  } = props;

  const ns = useNamespace('select');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);

  // Stable, instance-scoped prefix so every Option gets a unique DOM id that
  // `aria-activedescendant` on the combobox can point at, plus an id for the
  // listbox the combobox controls.
  const instanceId = useId();
  const listboxId = `${ns.b()}-${instanceId}-listbox`;
  const optionId = (val: SelectValue) =>
    `${ns.b()}-${instanceId}-option-${String(val)}`;

  const isControlled = value !== undefined;
  const [inner, setInner] = useState<SelectValue | SelectValue[] | undefined>(defaultValue);
  const current = isControlled ? value : inner;

  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [hovering, setHovering] = useState(false);
  const [hoveringValue, setHoveringValue] = useState<SelectValue | null>(null);

  // Read the Option children once per render to build the list.
  const options = useMemo<OptionMeta[]>(() => {
    const list: OptionMeta[] = [];
    Children.forEach(children, (child) => {
      if (!isOption(child)) {
        return;
      }
      const p = child.props;
      list.push({
        value: p.value,
        label: p.label ?? reactNodeToText(p.children) ?? String(p.value),
        disabled: p.disabled ?? false,
        element: child,
      });
    });
    return list;
  }, [children]);

  const selectedValues = useMemo<SelectValue[]>(() => {
    if (current === undefined || current === null || current === '') {
      return [];
    }
    return Array.isArray(current) ? current : [current];
  }, [current]);

  const isSelected = (val: SelectValue) => selectedValues.includes(val);

  const labelOf = (val: SelectValue): string =>
    options.find((option) => option.value === val)?.label ?? String(val);

  const hasValue = selectedValues.length > 0;

  const filtered = useMemo<OptionMeta[]>(() => {
    if (!filterable || query === '') {
      return options;
    }
    const needle = query.toLowerCase();
    return options.filter((option) => option.label.toLowerCase().includes(needle));
  }, [filterable, query, options]);

  const changeOpen = (next: boolean) => {
    if (next === open) {
      return;
    }
    setOpen(next);
    onVisibleChange?.(next);
    if (!next) {
      setQuery('');
      setHoveringValue(null);
    }
  };

  const commit = (next: SelectValue | SelectValue[]) => {
    if (!isControlled) {
      setInner(next);
    }
    onChange?.(next);
  };

  const handleSelect = (val: SelectValue) => {
    if (multiple) {
      const set = selectedValues.includes(val)
        ? selectedValues.filter((item) => item !== val)
        : [...selectedValues, val];
      commit(set);
      if (filterable) {
        setQuery('');
      }
      // Keep the dropdown open while picking multiple values.
    } else {
      commit(val);
      changeOpen(false);
    }
  };

  const handleRemoveTag = (val: SelectValue) => {
    const set = selectedValues.filter((item) => item !== val);
    commit(set);
    onRemoveTag?.(val);
  };

  const handleClear = () => {
    commit(multiple ? [] : ('' as SelectValue));
    setQuery('');
    onClear?.();
  };

  const moveHover = (delta: number) => {
    const enabled = filtered.filter((option) => !option.disabled);
    if (enabled.length === 0) {
      return;
    }
    const currentIndex = enabled.findIndex((option) => option.value === hoveringValue);
    const nextIndex =
      currentIndex === -1
        ? delta > 0
          ? 0
          : enabled.length - 1
        : (currentIndex + delta + enabled.length) % enabled.length;
    setHoveringValue(enabled[nextIndex].value);
  };

  // Highlight the first enabled option, used when ArrowDown opens the dropdown
  // so the keyboard highlight is exposed via aria-activedescendant immediately.
  const highlightFirst = () => {
    const enabled = filtered.filter((option) => !option.disabled);
    if (enabled.length > 0) {
      setHoveringValue(enabled[0].value);
    }
  };

  // Highlight the last enabled option, used when ArrowUp opens the dropdown.
  const highlightLast = () => {
    const enabled = filtered.filter((option) => !option.disabled);
    if (enabled.length > 0) {
      setHoveringValue(enabled[enabled.length - 1].value);
    }
  };

  const handleKeyDown = (event: KeyboardEvent<HTMLDivElement>) => {
    if (disabled) {
      return;
    }
    switch (event.key) {
      case 'Enter':
      case ' ': {
        if (event.key === ' ' && filterable && open) {
          // Allow typing spaces in the filter input.
          return;
        }
        event.preventDefault();
        if (!open) {
          changeOpen(true);
        } else if (hoveringValue !== null) {
          const target = filtered.find((option) => option.value === hoveringValue);
          if (target && !target.disabled) {
            handleSelect(target.value);
          }
        }
        break;
      }
      case 'ArrowDown': {
        event.preventDefault();
        if (!open) {
          changeOpen(true);
          // Land on the first option, matching the standard combobox pattern.
          highlightFirst();
        } else {
          moveHover(1);
        }
        break;
      }
      case 'ArrowUp': {
        event.preventDefault();
        if (!open) {
          changeOpen(true);
          // Land on the last option, matching the standard combobox pattern.
          highlightLast();
        } else {
          moveHover(-1);
        }
        break;
      }
      case 'Escape': {
        if (open) {
          event.preventDefault();
          changeOpen(false);
        }
        break;
      }
      default:
        break;
    }
  };

  const showClear = clearable && !disabled && hovering && hasValue;

  const rootClasses = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('disabled', disabled),
    ns.is('opened', open),
    ns.is('filterable', filterable),
    ns.is('multiple', multiple),
    className,
  );

  const wrapperClasses = cls(
    ns.e('wrapper'),
    ns.is('focus', open),
    ns.is('disabled', disabled),
  );

  const renderSelection = () => {
    if (multiple && hasValue) {
      return (
        <span className={ns.e('tags')}>
          {selectedValues.map((val) => (
            <span key={String(val)} className={ns.e('tag')}>
              <span className={ns.e('tag-text')}>{labelOf(val)}</span>
              {!disabled && (
                <button
                  type="button"
                  className={ns.e('tag-close')}
                  aria-label={`Remove ${labelOf(val)}`}
                  onMouseDown={(event) => event.preventDefault()}
                  onClick={(event) => {
                    event.stopPropagation();
                    handleRemoveTag(val);
                  }}
                >
                  <CloseIcon />
                </button>
              )}
            </span>
          ))}
          {filterable && (
            <input
              className={ns.e('input')}
              value={query}
              disabled={disabled}
              autoComplete="off"
              onChange={(event) => {
                setQuery(event.target.value);
                if (!open) {
                  changeOpen(true);
                }
              }}
              onClick={(event) => event.stopPropagation()}
              onMouseDown={(event) => event.stopPropagation()}
            />
          )}
        </span>
      );
    }

    if (filterable && open) {
      return (
        <input
          className={ns.e('input')}
          value={query}
          placeholder={hasValue ? labelOf(selectedValues[0]) : placeholder}
          disabled={disabled}
          autoComplete="off"
          autoFocus
          onChange={(event) => setQuery(event.target.value)}
          onClick={(event) => event.stopPropagation()}
        />
      );
    }

    if (hasValue) {
      return <span className={ns.e('selected')}>{labelOf(selectedValues[0])}</span>;
    }

    return <span className={ns.e('placeholder')}>{placeholder}</span>;
  };

  const trigger = (
    <div
      ref={ref}
      className={rootClasses}
      style={style}
      role="combobox"
      aria-label={ariaLabel}
      aria-labelledby={ariaLabelledby}
      aria-expanded={open}
      aria-haspopup="listbox"
      aria-controls={open ? listboxId : undefined}
      aria-activedescendant={
        open && hoveringValue !== null ? optionId(hoveringValue) : undefined
      }
      aria-disabled={disabled || undefined}
      tabIndex={disabled ? -1 : 0}
      onClick={() => {
        if (!disabled) {
          changeOpen(!open);
        }
      }}
      onKeyDown={handleKeyDown}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
    >
      <div className={wrapperClasses}>
        {renderSelection()}
        <span className={ns.e('suffix')}>
          {showClear ? (
            <span
              className={cls(ns.e('icon'), ns.e('clear'))}
              role="button"
              aria-label="Clear"
              onMouseDown={(event) => event.preventDefault()}
              onClick={(event) => {
                event.stopPropagation();
                handleClear();
              }}
            >
              <ClearIcon />
            </span>
          ) : (
            <span className={cls(ns.e('icon'), ns.e('caret'), ns.is('reverse', open))}>
              <CaretIcon />
            </span>
          )}
        </span>
      </div>
      {name && (
        <input
          type="hidden"
          name={name}
          value={multiple ? selectedValues.join(',') : (selectedValues[0] ?? '')}
        />
      )}
    </div>
  );

  const contextValue = {
    selectedValues,
    isSelected,
    onSelect: handleSelect,
    multiple,
    query,
    hoveringValue,
    optionId,
  };

  // The inner `<ul>` is the single source of `role="listbox"`. The shared
  // Popper renders a neutral floating shell (role="tooltip", which adds no
  // listbox/menu semantics), so exactly one listbox exists in the tree. The
  // combobox is linked to it explicitly via `aria-controls`.
  const dropdown = (
    <SelectContext.Provider value={contextValue}>
      <ul
        id={listboxId}
        className={ns.b('dropdown__list')}
        role="listbox"
        aria-multiselectable={multiple || undefined}
      >
        {loading ? (
          <li className={ns.b('dropdown__empty')}>Loading</li>
        ) : filtered.length === 0 ? (
          <li className={ns.b('dropdown__empty')}>
            {options.length === 0 ? noDataText : noMatchText}
          </li>
        ) : (
          filtered.map((option) => option.element)
        )}
      </ul>
    </SelectContext.Provider>
  );

  return (
    <Popper
      reference={trigger}
      trigger="manual"
      open={open}
      onOpenChange={changeOpen}
      placement="bottom-start"
      offset={4}
      matchWidth
      role="tooltip"
      disabled={disabled}
      popperClass={ns.e('popper')}
    >
      {dropdown}
    </Popper>
  );
});

.ec-select {
  --ec-select-text-color: var(--ec-text-color-regular);
  --ec-select-border-color: var(--ec-border-color);
  --ec-select-hover-border-color: var(--ec-border-color-hover);
  --ec-select-focus-border-color: var(--ec-color-primary);
  --ec-select-bg-color: var(--ec-fill-color-blank);
  --ec-select-icon-color: var(--ec-text-color-placeholder);
  --ec-select-placeholder-color: var(--ec-text-color-placeholder);
  --ec-select-border-radius: var(--ec-border-radius-base);
  --ec-select-height: var(--ec-component-size);
  --ec-select-font-size: var(--ec-font-size-base);

  display: inline-flex;
  width: 100%;
  box-sizing: border-box;
  font-size: var(--ec-select-font-size);
  cursor: pointer;
  outline: none;
}

.ec-select__wrapper {
  display: inline-flex;
  flex-grow: 1;
  align-items: center;
  gap: 6px;
  box-sizing: border-box;
  width: 100%;
  min-height: var(--ec-select-height);
  padding: 1px 11px;
  background-color: var(--ec-select-bg-color);
  border-radius: var(--ec-select-border-radius);
  transition: var(--ec-transition-box-shadow, var(--ec-transition-all));
  box-shadow: 0 0 0 1px var(--ec-select-border-color) inset;
}

.ec-select__wrapper:hover {
  box-shadow: 0 0 0 1px var(--ec-select-hover-border-color) inset;
}

.ec-select:focus-visible .ec-select__wrapper,
.ec-select__wrapper.is-focus {
  box-shadow: 0 0 0 1px var(--ec-select-focus-border-color) inset;
}

.ec-select__selected,
.ec-select__placeholder {
  flex-grow: 1;
  min-width: 0;
  overflow: hidden;
  line-height: calc(var(--ec-select-height) - 2px);
  white-space: nowrap;
  text-overflow: ellipsis;
}

.ec-select__selected {
  color: var(--ec-select-text-color);
}

.ec-select__placeholder {
  color: var(--ec-select-placeholder-color);
}

.ec-select__input {
  flex-grow: 1;
  width: 100%;
  min-width: 30px;
  padding: 0;
  margin: 0;
  font-family: inherit;
  font-size: inherit;
  line-height: calc(var(--ec-select-height) - 2px);
  color: var(--ec-select-text-color);
  background: none;
  border: none;
  outline: none;
  appearance: none;
}

.ec-select__input::placeholder {
  color: var(--ec-select-placeholder-color);
}

.ec-select__suffix {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  color: var(--ec-select-icon-color);
}

.ec-select__icon {
  display: inline-flex;
  align-items: center;
  font-size: var(--ec-font-size-base);
  color: var(--ec-select-icon-color);
}

.ec-select__caret {
  transition: transform var(--ec-transition-duration);
}

.ec-select__caret.is-reverse {
  transform: rotate(180deg);
}

.ec-select__clear {
  cursor: pointer;
  transition: var(--ec-transition-color);
}

.ec-select__clear:hover {
  color: var(--ec-text-color-secondary);
}

/* ---- Multiple tags ---- */
.ec-select__tags {
  display: inline-flex;
  flex-grow: 1;
  flex-wrap: wrap;
  align-items: center;
  gap: 4px;
  min-width: 0;
  padding: 3px 0;
}

.ec-select__tag {
  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  gap: 6px;
  height: 24px;
  padding: 0 9px;
  font-size: var(--ec-font-size-small);
  line-height: 1;
  white-space: nowrap;
  color: var(--ec-color-primary);
  background-color: var(--ec-color-primary-light-9);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-color-primary-light-8);
  border-radius: var(--ec-border-radius-base);
}

.ec-select__tag-text {
  display: inline-flex;
  align-items: center;
  overflow: hidden;
  text-overflow: ellipsis;
}

.ec-select__tag-close {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  width: 14px;
  height: 14px;
  padding: 0;
  margin: 0;
  font-size: 12px;
  color: inherit;
  cursor: pointer;
  background-color: transparent;
  border: none;
  border-radius: var(--ec-border-radius-circle);
  outline: none;
  transition: var(--ec-transition-all);
}

.ec-select__tag-close:hover {
  color: var(--ec-color-white);
  background-color: var(--ec-color-primary);
}

.ec-select__tags .ec-select__input {
  width: auto;
  flex-grow: 1;
}

/* ---- Disabled ---- */
.ec-select.is-disabled {
  cursor: not-allowed;
}

.ec-select.is-disabled .ec-select__wrapper {
  background-color: var(--ec-disabled-bg-color);
  box-shadow: 0 0 0 1px var(--ec-disabled-border-color) inset;
  cursor: not-allowed;
}

.ec-select.is-disabled .ec-select__wrapper:hover {
  box-shadow: 0 0 0 1px var(--ec-disabled-border-color) inset;
}

.ec-select.is-disabled .ec-select__selected,
.ec-select.is-disabled .ec-select__placeholder,
.ec-select.is-disabled .ec-select__input {
  color: var(--ec-disabled-text-color);
}

.ec-select.is-disabled .ec-select__input {
  cursor: not-allowed;
}

/* ---- Sizes ---- */
.ec-select--large {
  --ec-select-height: var(--ec-component-size-large);
  --ec-select-font-size: var(--ec-font-size-medium);
}

.ec-select--small {
  --ec-select-height: var(--ec-component-size-small);
  --ec-select-font-size: var(--ec-font-size-extra-small);
}

/* =========================================================
   Dropdown (rendered inside the shared ec-popper surface)
   ========================================================= */
.ec-select__popper {
  padding: 5px 0;
}

.ec-select-dropdown__list {
  box-sizing: border-box;
  max-height: 274px;
  padding: 0;
  margin: 0;
  overflow-y: auto;
  list-style: none;
}

.ec-select-dropdown__item {
  display: flex;
  align-items: center;
  box-sizing: border-box;
  height: 34px;
  padding: 0 20px;
  overflow: hidden;
  font-size: var(--ec-font-size-base);
  font-weight: var(--ec-font-weight-primary);
  line-height: 34px;
  white-space: nowrap;
  text-overflow: ellipsis;
  color: var(--ec-text-color-regular);
  cursor: pointer;
  transition: var(--ec-transition-color);
}

.ec-select-dropdown__item:hover,
.ec-select-dropdown__item.is-hovering {
  background-color: var(--ec-fill-color-light);
}

.ec-select-dropdown__item.is-selected {
  font-weight: var(--ec-font-weight-primary);
  color: var(--ec-color-primary);
}

.ec-select-dropdown__item.is-disabled {
  color: var(--ec-text-color-placeholder);
  cursor: not-allowed;
}

.ec-select-dropdown__item.is-disabled:hover {
  background-color: transparent;
}

.ec-select-dropdown__empty {
  box-sizing: border-box;
  padding: 10px 0;
  margin: 0;
  font-size: var(--ec-font-size-base);
  text-align: center;
  color: var(--ec-text-color-secondary);
  list-style: none;
}
